#include <iostream>
#include <cmath>
using namespace std;
class Solution {
public:
    int findGCD(int a, int b) {
        if (a == 0 || b == 0) {
            return abs(a + b);
        }
        while (b != 0) {
            a, b = b, a % b;
        }
        return abs(a);
    }
};

int main() {
    int a, b;
    cin >> a >> b;
    Solution solution;
    cout << solution.findGCD(a, b) << endl;
    return 0;
}
